Write-Host "=== Fix API ESM + runtime nodejs20 ===" -ForegroundColor Cyan
function Write-B64 { param($p,$b)
  $full = Join-Path (Get-Location).Path $p
  $dir = Split-Path $full -Parent
  if ($dir -and -not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
  $bytes = [Convert]::FromBase64String($b)
  $text = [System.Text.Encoding]::UTF8.GetString($bytes)
  [System.IO.File]::WriteAllText($full, $text, (New-Object System.Text.UTF8Encoding $false))
  Write-Host "  -> $p" -ForegroundColor Gray
}

Write-B64 "frontend\api\migrate.js" ""
Write-B64 "frontend\api\directions.js" ""
Write-B64 "frontend\api\engagements.js" ""
Write-B64 "frontend\api\alerts.js" ""
Write-B64 "frontend\api\budget.js" ""
Write-B64 "frontend\vercel.json" ""

git add -A
$c = git commit -m "fix: ESM export default + nodejs20 runtime pour API Neon" 2>&1
Write-Host "  $c" -ForegroundColor Gray
git push origin main 2>&1 | Select-Object -Last 2 | Write-Host
Write-Host "DONE - Vercel redeploy en cours" -ForegroundColor Green